preflight.run:
$ErrorActionPreference = "Stop"
$PSNativeCommandUseErrorActionPreference = $true
if ($env:SDKWORK_PACKAGE_PROFILE -eq "desktop" -and $env:SDKWORK_PACKAGE_PLATFORM -eq "linux") {
  sudo apt-get update
  sudo apt-get install -y libwebkit2gtk-4.1-dev libayatana-appindicator3-dev librsvg2-dev patchelf
}

build.run:
$ErrorActionPreference = "Stop"
$PSNativeCommandUseErrorActionPreference = $true
$env:CRAW_CHAT_RELEASE_VERSION = $env:SDKWORK_PACKAGE_VERSION
$env:SDKWORK_SHARED_SDK_GITHUB_TOKEN = $env:GH_TOKEN
if ($env:SDKWORK_PACKAGE_PROFILE -eq "server") {
  pnpm release:build:production -- --target server
} elseif ($env:SDKWORK_PACKAGE_PROFILE -eq "desktop") {
  pnpm release:build:production -- --target desktop --platform $env:SDKWORK_PACKAGE_PLATFORM --arch $env:SDKWORK_PACKAGE_ARCHITECTURE
} else {
  throw "Unsupported Craw Chat package profile $env:SDKWORK_PACKAGE_PROFILE"
}

stage.run:
$ErrorActionPreference = "Stop"
$PSNativeCommandUseErrorActionPreference = $true
function Resolve-CrawChatLegacyPackageId([string] $packageId) {
  switch ($packageId) {
    "linux-x64-server-tar-gz" { return "linux-x64-server-archive" }
    "linux-arm64-server-tar-gz" { return "linux-arm64-server-archive" }
    "macos-x64-server-tar-gz" { return "macos-x64-server-archive" }
    "macos-arm64-server-tar-gz" { return "macos-arm64-server-archive" }
    "windows-x64-server-zip" { return "windows-x64-server-archive" }
    "windows-arm64-server-zip" { return "windows-arm64-server-archive" }
    "linux-x64-desktop-zip" { return "linux-x64-desktop" }
    "linux-arm64-desktop-zip" { return "linux-arm64-desktop" }
    "macos-x64-desktop-zip" { return "macos-x64-desktop" }
    "macos-arm64-desktop-zip" { return "macos-arm64-desktop" }
    "windows-x64-desktop-zip" { return "windows-x64-desktop" }
    "windows-arm64-desktop-zip" { return "windows-arm64-desktop" }
    default { throw "Unsupported Craw Chat SDKWork package id $packageId" }
  }
}
$legacyPackageId = Resolve-CrawChatLegacyPackageId $env:SDKWORK_PACKAGE_ID
pnpm release:stage -- --package-id $legacyPackageId --version $env:SDKWORK_PACKAGE_VERSION

